        result = ((i >> 6) + i) & 7;                  // hash to channel index
        void* rcx_2 = *(arg1 + (result << 3) + 0x58); // channel lookup
        if (rcx_2) {
            while (*(rcx_2 + 0x54) != i) {            // walk linked list
                rcx_2 = *(rcx_2 + 0x98);
